CREATE EXTENSION IF NOT EXISTS postgis;

-- Static location index — no state column (state lives in Redis)
CREATE TABLE availability_spots (
    id          UUID             PRIMARY KEY,
    lot_id      UUID             NOT NULL,
    spot_number VARCHAR(10)      NOT NULL,
    floor       INT              NOT NULL DEFAULT 1,
    latitude    DOUBLE PRECISION NOT NULL,
    longitude   DOUBLE PRECISION NOT NULL,
    location    GEOGRAPHY(POINT, 4326) NOT NULL
);

CREATE INDEX idx_availability_spots_lot      ON availability_spots(lot_id);
CREATE INDEX idx_availability_spots_location ON availability_spots USING GIST(location);

